    /**
     * Checks if the given host resolves to a private or internal IP address.
     * This helps prevent SSRF attacks.
     * 
     * @param host the hostname to check
     * @return true if the host resolves to a private/internal IP, false otherwise
     */
    private boolean isPrivateOrInternalIp(String host) {
        try {
            InetAddress[] addresses = InetAddress.getAllByName(host);
            for (InetAddress addr : addresses) {
                // Check using built-in methods
                if (addr.isAnyLocalAddress() ||
                    addr.isLoopbackAddress() ||
                    addr.isSiteLocalAddress() ||
                    addr.isLinkLocalAddress()) {
                    return true;
                }

                // Additional check for IPv4 private ranges
                byte[] ipBytes = addr.getAddress();
                if (ipBytes.length == 4) {
                    // 10.0.0.0/8
                    if (ipBytes[0] == 10) {
                        return true;
                    }
                    // 172.16.0.0/12
                    if (ipBytes[0] == (byte) 172 && (ipBytes[1] >= 16 && ipBytes[1] <= 31)) {
                        return true;
                    }
                    // 192.168.0.0/16
                    if (ipBytes[0] == (byte) 192 && ipBytes[1] == (byte) 168) {
                        return true;
                    }
                    // 127.0.0.0/8
                    if (ipBytes[0] == 127) {
                        return true;
                    }
                    // 0.0.0.0
                    if (ipBytes[0] == 0 && ipBytes[1] == 0 && 
                        ipBytes[2] == 0 && ipBytes[3] == 0) {
                        return true;
                    }
                }
            }
        } catch (UnknownHostException e) {
            // If we can't resolve the host, let the HTTP client handle it
            return false;
        }
        return false;
    }
}
